  ('generalpolice-8b7f1efc-moex-00338', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-111-3a7b2121', 'sub-generalpolice-8b7f1efc-06', NULL, 'single_choice', '下列何者最符合韋伯（M.Weber）所述的理想官僚模式（idealbureaucracy）？', '["權宜變通，講求創新", "各司其職，謹守本分", "以人為本，因人設事", "講究溝通，充分協調"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:35+00:00", "source_pdf_sha1": "6adffb8bfe81", "answer_pdf_sha1": "d33e31e21078", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
